const e=JSON.parse('{"key":"v-d2310d7a","path":"/learningNote/Principles_of_Computer_Composition/","title":"计算机组成原理","lang":"zh-CN","frontmatter":{"title":"计算机组成原理","icon":"laptop-code","category":["Computer","basic"]},"headers":[{"level":2,"title":"简述","slug":"简述","link":"#简述","children":[]},{"level":2,"title":"机器数(Machine Number)","slug":"机器数-machine-number","link":"#机器数-machine-number","children":[{"level":3,"title":"1.简介","slug":"_1-简介","link":"#_1-简介","children":[]},{"level":3,"title":"2.计算标准 --- IEEE-754","slug":"_2-计算标准-ieee-754","link":"#_2-计算标准-ieee-754","children":[]},{"level":3,"title":"3.十进制转机器数(二进制)","slug":"_3-十进制转机器数-二进制","link":"#_3-十进制转机器数-二进制","children":[]},{"level":3,"title":"4.机器数(二进制)转十进制","slug":"_4-机器数-二进制-转十进制","link":"#_4-机器数-二进制-转十进制","children":[]},{"level":3,"title":"5.数值范围","slug":"_5-数值范围","link":"#_5-数值范围","children":[]},{"level":3,"title":"6.溢出错误与下溢错误","slug":"_6-溢出错误与下溢错误","link":"#_6-溢出错误与下溢错误","children":[]},{"level":3,"title":"7.机器数的上一位数/下一位数/机器精度(machine epsilon)","slug":"_7-机器数的上一位数-下一位数-机器精度-machine-epsilon","link":"#_7-机器数的上一位数-下一位数-机器精度-machine-epsilon","children":[]},{"level":3,"title":"8.真误差(true error)/真实相对误差(true relative error)","slug":"_8-真误差-true-error-真实相对误差-true-relative-error","link":"#_8-真误差-true-error-真实相对误差-true-relative-error","children":[]},{"level":3,"title":"9.舍入规则(Rounding Rule)","slug":"_9-舍入规则-rounding-rule","link":"#_9-舍入规则-rounding-rule","children":[]}]}],"git":{"createdTime":1693498440000,"updatedTime":1699169676000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":5}]},"readingTime":{"minutes":12.15,"words":3645},"filePathRelative":"learningNote/Principles_of_Computer_Composition/README.md","localizedDate":"2023年8月31日","excerpt":"<h2> 简述</h2>\\n<p>在这个文章当中都是有关计算机组成原理相关笔记。如有错误还请帮忙指正！</p>\\n<h2> 机器数(Machine Number)</h2>\\n<h3> 1.简介</h3>\\n<p>当一个十进制数转换为机器能够识别的二进制数时，能被完美以二进制进行表示而不存在无限不循环小数位的数被称为<strong>机器数(Machine Number)</strong>。</p>\\n<hr>\\n<h3> 2.计算标准 --- IEEE-754</h3>\\n<p>IEEE二进制浮点数算术标准（IEEE 754）是20世纪80年代以来最广泛使用的浮点数运算标准，为许多CPU与浮点运算器所采用。这个标准定义了表示浮点数的格式（包括负零-0）与反常值（denormal number）），一些特殊数值（无穷（Inf）与非数值（NaN）），以及这些数值的“浮点数运算符”；它也指明了四种数值舍入规则和五种例外状况（包括例外发生的时机与处理方式）。\\nIEEE 754规定了四种表示浮点数值的方式：单精确度（32位）、双精确度（64位）、延伸单精确度（43比特以上，很少使用）与延伸双精确度（79比特以上，通常以80位实现）。</p>"}');export{e as data};
